  return `<section class="page" data-page-view="fleet">${pageHeader('VEHICLE SYSTEM / REGISTRY', 'Fleet Registry', 'Saved ship instances backed by the fixed catalogue.', '<button class="button button-secondary" data-action="compare-ships"><span>COMP</span> Compare fleet</button><button class="button button-primary" data-action="add-ship"><span>REG</span> Add ship</button>')}<div class="system-strip"><span><b>SYS</b> VEHICLE MANAGEMENT</span><span><i></i> ${state.fleet.length} SAVED SHIPS</span><span>SOURCE // FIXED CAPACITY</span></div><div class="fleet-grid">${state.fleet.map((entry, index) => { const ship = DATA.ships.find(item => item.id === entry.shipId); const selected = entry.id === state.selectedShipId; return `<article class="panel ship-card-large${selected ? ' is-selected' : ''}" data-maker="${manufacturerTheme(ship)}"><div class="ship-card-top"><span>REG ${String(index + 1).padStart(3, '0')}</span><b>${manufacturerTheme(ship).toUpperCase()} // ${markupSafe(ship.variant).toUpperCase()}</b></div><div class="ship-visual"><span class="ship-schematic"><i></i><i></i><i></i></span><small>VEHICLE PROFILE // ${markupSafe(ship.family).toUpperCase()}</small></div><div class="ship-record"><div class="chip-row"><span class="chip">${markupSafe(ship.family)}</span><span class="chip info">${markupSafe(ship.variant)}</span></div><h3>${markupSafe(fleetShipLabel(entry, ship))}</h3><p>${markupSafe(ship.maker)} · ${markupSafe(ship.role)}</p><div class="ship-meta"><div><span>Cargo capacity</span><strong>${money(ship.capacity)} <small>SCU</small></strong></div><div class="button-row"><button class="button button-small ${selected ? 'button-primary' : 'button-secondary'}" data-select-ship="${entry.id}">${selected ? 'Selected' : 'Use in Planner'}</button><button class="button button-small button-danger" data-remove-ship="${entry.id}"${state.fleet.length === 1 ? ' disabled' : ''}>Remove</button></div></div></div></article>`; }).join('')}</div></section>`;
